  ('bookkeeper-moex-01468', 'bookkeeper', 'bookkeeper-moex-102-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '試問下列那種方法，可有效縮短營業週期（operating cycle）？①提高存貨週轉率  ②提高存貨週轉天數', '["提高應收帳款週轉率", "降低應收帳款週轉天數", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "d0956d934e59", "answer_pdf_sha1": "ddd6e86d263b", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01469', 'bookkeeper', 'bookkeeper-moex-102-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '順心公司於X1年初購入設備，成本$400,000，估計耐用年限4年，無殘值，採直線法提列折舊。X3年 初順心公司支付$125,000加以整修，預估可使設備延長3年之使用年限；則X3年底順心公司該設備之帳 面金額為：', '["$244,000", "$260,000", "$325,000", "$420,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "d0956d934e59", "answer_pdf_sha1": "ddd6e86d263b", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01470', 'bookkeeper', 'bookkeeper-moex-102-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', 'A公司帳載現金餘額為$85,000，已知公司開立支付電話費之支票，面額為$7,200，帳上卻誤記為$2,700；又 銀行代收票據已兌現$30,000，扣繳水電費$8,000，公司皆尚未入帳，試問公司正確的現金餘額應為：', '["$80,500", "$102,500", "$107,000", "$115,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "d0956d934e59", "answer_pdf_sha1": "ddd6e86d263b", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01471', 'bookkeeper', 'bookkeeper-moex-102-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '臺北公司X5年期初存貨$150,000，X5年度進貨$450,000，進貨退出$10,000，進貨折讓$4,000，進貨運費 $26,000，銷貨$500,000，銷貨退回$10,000，銷貨折讓$5,000，試問臺北公司X5年可供銷貨商品成本為多 少？', '["$490,000", "$585,000", "$612,000", "$617,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "d0956d934e59", "answer_pdf_sha1": "ddd6e86d263b", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01472', 'bookkeeper', 'bookkeeper-moex-102-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '麗安公司本月份開始營運，並完成2,000件產品，期末在製品100件（完工程度：原料100%，加工成本 50%）。若本月份耗用原料$4,200，加工成本$6,150，則期末在製品成本為多少？', '["$350", "$420", "$500", "$615"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "d0956d934e59", "answer_pdf_sha1": "ddd6e86d263b", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01473', 'bookkeeper', 'bookkeeper-moex-102-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '安西公司以成本$1,000,000，帳面價值$800,000，公平市價$300,000的汽車，換入公平市價$260,000的機 器，並收到現金$40,000，此一交換具商業實質意涵，試問安西公司換入機器之成本應記錄多少？', '["$300,000", "$260,000", "$760,000", "$160,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "d0956d934e59", "answer_pdf_sha1": "ddd6e86d263b", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
