  ('bookkeeper-moex-01475', 'bookkeeper', 'bookkeeper-moex-102-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '三洋公司X1年底有負債$100,000、資產$750,000。年初有負債$30,000，X1年中股東投入$100,000；X1年 度總收入為$360,000，總費用為$320,000，試問X1年初資產總額為多少？', '["$140,000", "$510,000", "$540,000", "$650,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:27+00:00", "source_pdf_sha1": "d0956d934e59", "answer_pdf_sha1": "ddd6e86d263b", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
